final class RotatingRenderer: NSObject, MTKViewDelegate {
    var device: MTLDevice!
    var queue: MTLCommandQueue!
    var pipeline: MTLRenderPipelineState!
    var buffer: MTLBuffer!
    var time: Float = 0

    init(view: MTKView) {
        super.init()
        device = view.device
        queue = device.makeCommandQueue()

        let vertices: [Float] = [ 0,0.5,0,  -0.5,-0.5,0,  0.5,-0.5,0 ]
        buffer = device.makeBuffer(bytes: vertices, length: vertices.count*4, options: [])

        let lib = device.makeDefaultLibrary()!
        let pipelineDesc = MTLRenderPipelineDescriptor()
        pipelineDesc.vertexFunction = lib.makeFunction(name: "rotating_vertex")
        pipelineDesc.fragmentFunction = lib.makeFunction(name: "color_fragment")
        pipelineDesc.colorAttachments[0].pixelFormat = view.colorPixelFormat
        pipeline = try! device.makeRenderPipelineState(descriptor: pipelineDesc)
    }

    func draw(in view: MTKView) {
        time += 0.01
        guard let drawable = view.currentDrawable,
              let pass = view.currentRenderPassDescriptor else { return }

        let command = queue.makeCommandBuffer()!
        let enc = command.makeRenderCommandEncoder(descriptor: pass)!
        enc.setRenderPipelineState(pipeline)
        enc.setVertexBuffer(buffer, offset: 0, index: 0)
        enc.setVertexBytes(&time, length: 4, index: 1)
        enc.drawPrimitives(type: .triangle, vertexStart: 0, vertexCount: 3)
        enc.endEncoding()
        command.present(drawable)
        command.commit()
    }
}

