vertex VertexOut vertex_main(const device float* verts [[buffer(0)]],
                             const device float3* normals [[buffer(1)]],
                             constant float3& lightDir [[buffer(2)]],
                             uint id [[vertex_id]]) {
    float3 pos = float3(verts[id*6], verts[id*6+1], verts[id*6+2]);
    float3 col = float3(verts[id*6+3], verts[id*6+4], verts[id*6+5]);

