fragment float4 fragment_main(float2 uv [[stage_in]],
                             texture2d<float> albedo [[texture(0)]],
                             texture2d<float> normalMap [[texture(1)]]) {

    constexpr sampler s(filter::linear);

    float3 baseColor = albedo.sample(s, uv).rgb;
    float3 normal    = normalMap.sample(s, uv).rgb * 2.0 - 1.0;

    float3 lightDir = normalize(float3(0.3, 0.6, 1.0));
    float diffuse   = max(dot(normal, lightDir), 0.0);

    return float4(baseColor * diffuse, 1.0);
}

#include <metal_stdlib>
using namespace metal;

fragment float4 fragment_main(float3 normal [[stage_in]], float3 pos [[position]]) {
    float3 N = normalize(normal);
    float3 L = normalize(float3(0.4, 0.8, 1.0));
    float3 V = normalize(-pos);

    float3 R = reflect(-L, N);

    float diffuse = max(dot(N, L), 0.0);
    float spec    = pow(max(dot(R, V), 0.0), 32.0); / Shininess

    float3 color = diffuse * float3(0.5, 0.5, 1.0) + spec * float3(1.0, 1.0, 1.0);

    return float4(color, 1.0);
}

