fragment float4 bloom_extract(texture2d<float> tex [[texture(0)]], float2 uv [[stage_in]]) {
    constexpr sampler s(filter::linear);
    float3 c = tex.sample(s, uv).rgb;

    float brightness = max(max(c.r, c.g), c.b);

    if (brightness > 0.7) { return float4(c,1.0); }
    else                  { return float4(0,0,0,1); }
}

