fragment float4 dissolve_frag(float2 uv [[stage_in]],
                              texture2d<float> tex [[texture(0)]],
                              texture2d<float> noiseTex [[texture(1)]],
                              constant float& threshold [[buffer(0)]]) {

    constexpr sampler s(filter::linear);
    float4 base = tex.sample(s, uv);
    float noise = noiseTex.sample(s, uv).r;

    if (noise < threshold) {
        return base; / sichtbar
    }

    float edge = smoothstep(threshold, threshold + 0.1, noise);
    return float4(edge, edge*0.3, 0.0, 1.0); / Feuer-Rand
}
